const MT_REGISTRY_KEY = 'fb_tenants';       // localStorage key for tenant list
const MT_ACTIVE_KEY   = 'fb_active_tenant'; // localStorage key for current tenant
const MT_SUPER_KEY    = 'fb_super_session'; // localStorage key for super admin session
const MT_DB_VERSION   = 4;

// Super admin credentials — defaults, overridden by localStorage if changed
const SUPER_ADMIN_DEFAULTS = {
  username: 'superadmin',
  passHash: '357db263b95cb33ae4ec8dffed73206e8bf7c162895b0591fbd387e3e2f8c6ae', // FuelBunk@Super2026
};
function mt_getSuperCreds() {
  try {
    const stored = JSON.parse(localStorage.getItem('fb_super_creds') || 'null');
    return stored || SUPER_ADMIN_DEFAULTS;
  } catch { return SUPER_ADMIN_DEFAULTS; }
}
function mt_saveSuperCreds(username, passHash) {
  localStorage.setItem('fb_super_creds', JSON.stringify({ username, passHash }));
}

// ── Tenant Registry (stored in localStorage) ──
function mt_getTenants() {
  try { return JSON.parse(localStorage.getItem(MT_REGISTRY_KEY) || '[]'); } catch { return []; }
}
function mt_saveTenants(tenants) {
  localStorage.setItem(MT_REGISTRY_KEY, JSON.stringify(tenants));
}
function mt_getActiveTenant() {
  try {
    const raw = localStorage.getItem(MT_ACTIVE_KEY);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch { return null; }
}
function mt_setActiveTenant(tenant) {
  localStorage.setItem(MT_ACTIVE_KEY, JSON.stringify(tenant));
  // CROSS-TENANT FIX: Cache tenant ID in a simple flat key so all modules
  // (_tenantKey in employee.js, _scopedKey in api-client.js, _tenantPrefix in autosave.js)
  // can scope their localStorage keys without needing to parse the full tenant JSON.
  if (tenant && tenant.id) {
    localStorage.setItem('fb_active_tenant_id', String(tenant.id));
  } else {
    localStorage.removeItem('fb_active_tenant_id');
  }
}
function mt_clearActiveTenant() {
  localStorage.removeItem(MT_ACTIVE_KEY);
  localStorage.removeItem(MT_SUPER_KEY);
  localStorage.removeItem('fb_active_tenant_id');
}
function mt_dbName(tenantId) {
  return 'FuelBunkPro_' + tenantId;
}

// ── Super Admin Session ──
function mt_getSuperSession() {
  try { return JSON.parse(localStorage.getItem(MT_SUPER_KEY) || 'null'); } catch { return null; }
}
function mt_saveSuperSession() {
  localStorage.setItem(MT_SUPER_KEY, JSON.stringify({ loggedIn: true, at: Date.now() }));
}
function mt_clearSuperSession() {
  localStorage.removeItem(MT_SUPER_KEY);
}
function mt_isSuperLoggedIn() {
  const s = mt_getSuperSession();
  if (!s || !s.loggedIn) return false;
  if (Date.now() - s.at > 4 * 60 * 60 * 1000) { mt_clearSuperSession(); return false; } // 4hr
  return true;
}

// ── Tenant Selector UI ──
// ── OMC Selector helpers ──────────────────────────────────────────────────
const _OMC_OPTS = [
  {id:'iocl',    label:'IOCL',    sub:'Indian Oil',     color:'#ef4444'},
  {id:'bpcl',    label:'BPCL',    sub:'Bharat Petro',   color:'#3b82f6'},
  {id:'hpcl',    label:'HPCL',    sub:'Hindustan',      color:'#22c55e'},
  {id:'mrpl',    label:'MRPL',    sub:'Mangalore',      color:'#f97316'},
  {id:'private', label:'Private', sub:'Independent',    color:'#9498a5'},
];
function mt_omcSelectorHTML(selected) {
  var cur = selected || 'iocl';
  var btns = _OMC_OPTS.map(function(o) {
    var sel  = cur === o.id;
    var bc   = sel ? o.color : 'var(--border)';
    var bg   = sel ? o.color + '18' : 'var(--bg-0)';
    var lc   = sel ? o.color : 'var(--text-2)';
    return '<label style="flex:1;min-width:52px;cursor:pointer">'
      + '<input type="radio" name="tOmc" value="' + o.id + '" ' + (sel ? 'checked' : '')
      + ' style="display:none" onchange="mt_omcSelect(this)">'
      + '<div data-omc-color="' + o.color + '" class="omc-opt" style="border:2px solid ' + bc + ';background:' + bg + ';border-radius:8px;padding:8px 4px;text-align:center;transition:all 0.15s">'
      + '<div class="omc-lb" style="font-size:12px;font-weight:800;color:' + lc + '">' + o.label + '</div>'
      + '<div style="font-size:9px;color:var(--text-3);margin-top:1px">' + o.sub + '</div>'
      + '</div></label>';
  }).join('');
  return '<div class="form-group" style="margin-top:4px">'
    + '<label class="form-label">Oil Marketing Company (OMC)</label>'
    + '<div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:6px">' + btns + '</div></div>';
}
function mt_omcSelect(radio) {
  var row = radio.closest('div[style*="display:flex"]') || radio.closest('.form-group');
  if (!row) return;
  row.querySelectorAll('.omc-opt').forEach(function(d) {
    d.style.borderColor = 'var(--border)';
    d.style.background  = 'var(--bg-0)';
    var lb = d.querySelector('.omc-lb');
    if (lb) lb.style.color = 'var(--text-2)';
  });
  var chosen = radio.nextElementSibling;
  if (chosen) {
    var col = chosen.getAttribute('data-omc-color') || '#ef4444';
    chosen.style.borderColor = col;
    chosen.style.background  = col + '18';
    var lb = chosen.querySelector('.omc-lb');
    if (lb) lb.style.color = col;
  }
}

